1	/**
2	 * TypeScript types for .yoke.yml configuration.
3	 *
4	 * Derived from docs/design/schemas/yoke-config.schema.json (JSON Schema draft-2020-12).
5	 * Version "1" is the only supported version.
6	 *
7	 * Two forms:
8	 *   RawConfig      — direct YAML parse output; path fields may be relative strings.
9	 *   ResolvedConfig — RawConfig with all path fields guaranteed to be absolute,
10	 *                    plus a `configDir` field. All downstream modules consume
11	 *                    ResolvedConfig only.
12	 *
13	 * Resolved at load time (relative → absolute, base = .yoke.yml directory):
14	 *   phases[*].prompt_template
15	 *   phases[*].cwd                          (if present)
16	 *   phases[*].output_artifacts[*].schema   (if present)
17	 *   worktrees.teardown.script              (if present)
18	 *
19	 * NOT resolved (runtime-relative to the worktree, unknown at load time):
20	 *   pipeline.stages[*].items_from
21	 *   phases[*].output_artifacts[*].path
22	 */
23	
24	// ---------------------------------------------------------------------------
25	// Action grammar (mirrors docs/design/schemas/pre-post-action-grammar.md)
26	// ---------------------------------------------------------------------------
27	
28	export type RetryMode =
29	  | 'continue'
30	  | 'fresh_with_failure_summary'
31	  | 'fresh_with_diff'
32	  | 'awaiting_user';
33	
34	export type ActionValue =
35	  | 'continue'
36	  | 'stop-and-ask'
37	  | 'stop'
38	  | { goto: string; max_revisits?: number }
39	  | { retry: { mode: 'continue' | 'fresh_with_failure_summary' | 'fresh_with_diff'; max: number } }
40	  | { fail: { reason: string } };
41	
42	/** Keys are exit-code strings ("0"–"255") or the wildcard "*". */
43	export type ActionsMap = Record<string, ActionValue>;
44	
45	// ---------------------------------------------------------------------------
46	// Pre / post commands
47	// ---------------------------------------------------------------------------
48	
49	export interface PrePostCommand {
50	  name: string;
51	  /** argv-form; spawned with shell: false */
52	  run: string[];
53	  timeout_s?: number;
54	  env?: Record<string, string>;
55	  actions: ActionsMap;
56	}
57	
58	// ---------------------------------------------------------------------------
59	// Phase
60	// ---------------------------------------------------------------------------
61	
62	export interface OutputArtifact {
63	  /** Relative to worktree (not resolved at load time). */
64	  path: string;
65	  /** Path to a JSON Schema file. Absolute in ResolvedConfig. */
66	  schema?: string;
67	  required?: boolean;
68	}
69	
70	export interface Heartbeat {
71	  activity_timeout_s?: number;
72	  /** Tool-name → wall-clock budget in seconds. */
73	  per_tool_budgets?: Record<string, number>;
74	}
75	
76	export interface Phase {
77	  command: string;
78	  args: string[];
79	  env?: Record<string, string>;
80	  /** Absolute in ResolvedConfig (if present). */
81	  cwd?: string;
82	  /** Absolute in ResolvedConfig. */
83	  prompt_template: string;
84	  output_artifacts?: OutputArtifact[];
85	  max_outer_retries?: number;
86	  retry_ladder?: RetryMode[];
87	  heartbeat?: Heartbeat;
88	  pre?: PrePostCommand[];
89	  post?: PrePostCommand[];
90	}
91	
92	// ---------------------------------------------------------------------------
93	// Pipeline / stages
94	// ---------------------------------------------------------------------------
95	
96	export interface ItemsDisplay {
97	  title?: string;
98	  subtitle?: string;
99	}
100	
101	export interface Stage {
102	  id: string;
103	  run: 'once' | 'per-item';
104	  /** Ordered phase keys referencing the top-level phases map. */
105	  phases: string[];
106	  needs_approval?: boolean;
107	  /** Relative to worktree — NOT resolved at load time. */
108	  items_from?: string;
109	  items_list?: string;
110	  items_id?: string;
111	  items_depends_on?: string;
112	  items_display?: ItemsDisplay;
113	}
114	
115	export interface Pipeline {
116	  stages: Stage[];
117	}
118	
119	// ---------------------------------------------------------------------------
120	// Top-level optional sections
121	// ---------------------------------------------------------------------------
122	
123	export interface Project {
124	  name: string;
125	}
126	
127	export interface WorktreesBootstrap {
128	  commands?: string[];
129	}
130	
131	export interface WorktreesTeardown {
132	  /** Absolute in ResolvedConfig (if present). */
133	  script?: string;
134	}
135	
136	export interface Worktrees {
137	  base_dir?: string;
138	  branch_prefix?: string;
139	  auto_cleanup?: boolean;
140	  cleanup_tool?: 'git' | 'lazyworktree' | 'custom';
141	  bootstrap?: WorktreesBootstrap;
142	  teardown?: WorktreesTeardown;
143	}
144	
145	export interface NotificationMechanism {
146	  type: 'browser_push' | 'macos_native';
147	}
148	
149	export interface Notifications {
150	  enabled?: boolean;
151	  severity_map?: Record<string, string>;
152	  mechanisms?: NotificationMechanism[];
153	}
154	
155	export interface Github {
156	  enabled?: boolean;
157	  auto_pr?: boolean;
158	  pr_target_branch?: string;
159	  auth_order?: Array<'env:GITHUB_TOKEN' | 'gh:auth:token'>;
160	  attach_artifacts_to_pr?: boolean;
161	  link_issues?: boolean;
162	}
163	
164	export type SqliteRetention = 'forever' | { max_age_days: number };
165	
166	export interface RetentionStreamJsonLogs {
167	  max_age_days?: number;
168	  max_total_bytes?: number;
169	}
170	
171	export interface Retention {
172	  sqlite?: SqliteRetention;
173	  stream_json_logs?: RetentionStreamJsonLogs;
174	  worktrees?: 'workflow-completion' | 'manual' | 'on-disk-pressure';
175	}
176	
177	export interface Logging {
178	  retain_stream_json?: boolean;
179	}
180	
181	export interface Runtime {
182	  keep_awake?: boolean;
183	}
184	
185	export interface RateLimit {
186	  handling?: 'passive';
187	  /** v1.1 only; rejected at load time in v1 by the schema. */
188	  usage_pause_threshold?: number;
189	}
190	
191	export interface Ui {
192	  port?: number;
193	  bind?: '127.0.0.1';
194	  auth?: false;
195	}
196	
197	// ---------------------------------------------------------------------------
198	// Root config types
199	// ---------------------------------------------------------------------------
200	
201	/**
202	 * Raw config as parsed from .yoke.yml — before path resolution.
203	 * Relative path fields are still relative strings in this type.
204	 */
205	export interface RawConfig {
206	  version: string;
207	  project: Project;
208	  pipeline: Pipeline;
209	  /** Keys are phase names referenced by pipeline stages. */
210	  phases: Record<string, Phase>;
211	  worktrees?: Worktrees;
212	  notifications?: Notifications;
213	  github?: Github;
214	  retention?: Retention;
215	  logging?: Logging;
216	  runtime?: Runtime;
217	  rate_limit?: RateLimit;
218	  ui?: Ui;
219	  safety_mode?: 'strict' | 'default' | 'yolo';
220	}
221	
222	/**
223	 * Config with all relative paths resolved to absolute paths, using the
224	 * .yoke.yml directory as the base. All downstream modules consume only
225	 * this type — never RawConfig.
226	 */
227	export type ResolvedConfig = RawConfig & {
228	  /** Absolute path of the directory containing .yoke.yml. */
229	  configDir: string;
230	};
