1	/**
2	 * Structured error types for the config loader.
3	 *
4	 * Every failure from loadConfig() is a ConfigLoadError; callers narrow
5	 * on `detail.kind` to handle specific failure classes rather than
6	 * pattern-matching error messages.
7	 */
8	
9	/** Simplified AJV error shape retained on ConfigLoadError for programmatic use. */
10	export interface ValidationError {
11	  instancePath: string;
12	  schemaPath: string;
13	  message: string;
14	  params: Record<string, unknown>;
15	}
16	
17	export type ConfigErrorDetail =
18	  | { kind: 'not_found'; message: string; path: string }
19	  | { kind: 'parse_error'; message: string }
20	  | { kind: 'version_error'; message: string; received: unknown }
21	  | { kind: 'validation_error'; message: string; errors: ValidationError[] };
22	
23	/**
24	 * Thrown by loadConfig() for every failure class:
25	 *
26	 *   not_found        — file missing or unreadable (ENOENT, EACCES, …)
27	 *   parse_error      — empty file or YAML syntax error
28	 *   version_error    — missing `version` field or version !== "1"
29	 *   validation_error — AJV schema violation (unknown key, wrong type, …)
30	 */
31	export class ConfigLoadError extends Error {
32	  readonly detail: ConfigErrorDetail;
33	
34	  constructor(detail: ConfigErrorDetail) {
35	    super(detail.message);
36	    this.name = 'ConfigLoadError';
37	    this.detail = detail;
38	    // Maintains proper prototype chain in transpiled environments.
39	    Object.setPrototypeOf(this, new.target.prototype);
40	  }
41	}
