1	/**
2	 * Synchronous .yoke.yml loader.
3	 *
4	 * Reads the file, parses YAML 1.2, performs a version pin check, validates
5	 * against yoke-config.schema.json via AJV, and resolves all relative paths to
6	 * absolute before returning. No async code paths — synchronous throughout to
7	 * match better-sqlite3 parity on the startup critical path.
8	 *
9	 * Throws ConfigLoadError (never a raw Error) for every failure class:
10	 *   not_found        — file missing or unreadable
11	 *   parse_error      — empty file or YAML syntax error
12	 *   version_error    — missing `version` field or version !== "1"
13	 *   validation_error — AJV schema violation (unknown key, wrong type, …)
14	 */
15	
16	import fs from 'node:fs';
17	import path from 'node:path';
18	import { fileURLToPath } from 'node:url';
19	import { parse as parseYaml } from 'yaml';
20	import Ajv2020 from 'ajv/dist/2020.js';
21	import type { ErrorObject, AnySchema } from 'ajv';
22	import { ConfigLoadError, type ValidationError } from './errors.js';
23	import { resolveConfig } from './resolve.js';
24	import type { RawConfig, ResolvedConfig } from '../../shared/types/config.js';
25	
26	// ---------------------------------------------------------------------------
27	// AJV setup — compiled once at module initialisation, never mutated.
28	// ---------------------------------------------------------------------------
29	
30	const SCHEMA_PATH = fileURLToPath(
31	  new URL('../../../docs/design/schemas/yoke-config.schema.json', import.meta.url),
32	);
33	
34	// readFileSync here is not a violation of the "no I/O in resolver" rule;
35	// this is the loader, and the schema is infrastructure, not user data.
36	const SCHEMA_JSON = JSON.parse(fs.readFileSync(SCHEMA_PATH, 'utf8')) as AnySchema;
37	
38	// allErrors: true — report every violation, not just the first.
39	const ajv = new Ajv2020({ allErrors: true });
40	const validate = ajv.compile(SCHEMA_JSON);
41	
42	// ---------------------------------------------------------------------------
43	// Public API
44	// ---------------------------------------------------------------------------
45	
46	/**
47	 * Load, validate, and resolve a .yoke.yml file synchronously.
48	 *
49	 * @param configPath — absolute or cwd-relative path to the .yoke.yml file.
50	 * @returns ResolvedConfig with all relative paths converted to absolute.
51	 * @throws ConfigLoadError on any failure (structured kind discriminant).
52	 */
53	export function loadConfig(configPath: string): ResolvedConfig {
54	  // 1. Read file — I/O lives here, not in the resolver.
55	  let rawYaml: string;
56	  try {
57	    rawYaml = fs.readFileSync(configPath, 'utf8');
58	  } catch (err) {
59	    throw new ConfigLoadError({
60	      kind: 'not_found',
61	      path: configPath,
62	      message: `Cannot read ${configPath}: ${(err as NodeJS.ErrnoException).message}`,
63	    });
64	  }
65	
66	  // 2. Parse YAML 1.2.
67	  //    yaml@2.x defaults to YAML 1.2 — on/off/yes/no are strings, not bools.
68	  //    version: 1 (bare integer) parses as number 1, caught below.
69	  let parsed: unknown;
70	  try {
71	    parsed = parseYaml(rawYaml);
72	  } catch (err) {
73	    throw new ConfigLoadError({
74	      kind: 'parse_error',
75	      message: `YAML parse error in ${configPath}: ${(err as Error).message}`,
76	    });
77	  }
78	
79	  // 3. Reject empty / null documents (yaml@2 returns undefined for blank input).
80	  if (parsed === null || parsed === undefined) {
81	    throw new ConfigLoadError({
82	      kind: 'parse_error',
83	      message: `${configPath} is empty or contains only a null document`,
84	    });
85	  }
86	
87	  // 4. Version pin check — runs before AJV so the error message is specific.
88	  //    Review criterion: "names the current version and the received value."
89	  if (typeof parsed !== 'object' || !('version' in (parsed as object))) {
90	    throw new ConfigLoadError({
91	      kind: 'version_error',
92	      received: undefined,
93	      message:
94	        `${configPath}: missing required field 'version'. ` +
95	        `This harness requires version: "1".`,
96	    });
97	  }
98	  const receivedVersion = (parsed as Record<string, unknown>)['version'];
99	  if (receivedVersion !== '1') {
100	    throw new ConfigLoadError({
101	      kind: 'version_error',
102	      received: receivedVersion,
103	      message:
104	        `${configPath}: version ${JSON.stringify(receivedVersion)} is not supported. ` +
105	        `This harness requires version: "1".`,
106	    });
107	  }
108	
109	  // 5. AJV validation (additionalProperties: false everywhere in schema).
110	  const valid = validate(parsed);
111	  if (!valid) {
112	    const ajvErrors = validate.errors ?? [];
113	    throw new ConfigLoadError({
114	      kind: 'validation_error',
115	      message: formatAjvErrors(ajvErrors, configPath),
116	      errors: ajvErrors.map(toValidationError),
117	    });
118	  }
119	
120	  // 6. Resolve relative paths — pure, no I/O.
121	  const configDir = path.dirname(path.resolve(configPath));
122	  return resolveConfig(parsed as RawConfig, configDir);
123	}
124	
125	// ---------------------------------------------------------------------------
126	// Internal helpers
127	// ---------------------------------------------------------------------------
128	
129	/**
130	 * Format AJV errors into a human-readable string that satisfies the
131	 * acceptance criterion: "include the schema path and the offending value."
132	 *
133	 * Each line includes:
134	 *   - instancePath (where in the data)
135	 *   - message (what went wrong)
136	 *   - offending property name (for additionalProperties) or expected value
137	 *   - schemaPath (pointer into the schema)
138	 */
139	function formatAjvErrors(errors: ErrorObject[], configPath: string): string {
140	  const lines = [`Config validation failed for ${configPath}:`];
141	  for (const err of errors) {
142	    const where = err.instancePath === '' ? '(root)' : err.instancePath;
143	    const offending = describeOffending(err);
144	    lines.push(`  • ${where}: ${err.message}${offending} (schema: ${err.schemaPath})`);
145	  }
146	  return lines.join('\n');
147	}
148	
149	/**
150	 * Extract a short "offending value" description from AJV error params.
151	 * Handles the two most important cases:
152	 *   - additionalProperties: names the unknown key
153	 *   - const:                names the expected constant value
154	 */
155	function describeOffending(err: ErrorObject): string {
156	  if (err.keyword === 'additionalProperties') {
157	    const p = (err.params as { additionalProperty?: string }).additionalProperty;
158	    return p !== undefined ? `, offending property: "${p}"` : '';
159	  }
160	  if (err.keyword === 'const') {
161	    const v = (err.params as { allowedValue?: unknown }).allowedValue;
162	    return v !== undefined ? `, expected: ${JSON.stringify(v)}` : '';
163	  }
164	  return '';
165	}
166	
167	function toValidationError(err: ErrorObject): ValidationError {
168	  return {
169	    instancePath: err.instancePath,
170	    schemaPath: err.schemaPath,
171	    message: err.message ?? 'unknown AJV error',
172	    params: err.params as Record<string, unknown>,
173	  };
174	}
